// 构建分享链接
const shareLink = computed(() => {
  const baseUrl = import.meta.env.VITE_APP_BASE_URL || import.meta.env.BASE_URL || '';
  const shareUrl=new URL(`${window.location.origin}${baseUrl}share/link/${props.taskId}`)
  shareUrl.searchParams.append('shareId', shareId.value);
  return shareUrl.toString();
});

// 复制分享链接
const handleCopy = async () => {
  try {
    await navigator.clipboard.writeText(shareLink.value);
    message.success('分享链接已复制');
  } catch (error) {
    message.error('复制失败，请手动复制');
  }
};

// 统一的分享处理函数
const handlePlatformShare = (platformKey) => {
  const title = encodeURIComponent('来看看这个3D模型');
  const summary = encodeURIComponent('来看看这个3D模型');
  const url = encodeURIComponent(shareLink.value);
  
  switch (platformKey) {
    case 'wechat':
      message.info('请使用微信扫一扫分享');
      break;
    case 'bilibili':
      window.open(`https://share.bilibili.com/share?title=${title}&text=${url}`, '_blank');
      break;
    case 'twitter':
      window.open(`https://twitter.com/intent/tweet?text=${title}&url=${url}`, '_blank');
      break;
    case 'qq':
      window.open(`https://connect.qq.com/widget/shareqq/index.html?url=${url}&title=${encodeURIComponent('3D模型分享')}&summary=${summary}`, '_blank');
      break;
    case 'weibo':
      window.open(`https://service.weibo.com/share/share.php?url=${url}&title=${title}`, '_blank');
      break;
    case 'linkedin':
      window.open(`https://www.linkedin.com/sharing/share-offsite/?url=${url}`, '_blank');
      break;
    default:
      break;
  }
};

onMounted(async () => {
  const response = await ApiServer.request(
    {
      url: API.BASE_URL+ API.SHARE_CREATE,
      method: 'POST',
      data: {
        taskId: props.taskId,
        expireAt: 0, 
        official: props.official
      }
    }
    
  )
  console.log(response.data)
  const shareUrl = new URL(response.data.href);
  shareId.value = shareUrl.searchParams.get('shareId');
});
</script>

